#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7;

int solve(long long n){
    int ans[3][3],base[3][3],tmp[3][3];
    ans[1][1]=ans[2][2]=1,ans[1][2]=ans[2][1]=0;
    base[1][1]=0,base[1][2]=base[2][1]=base[2][2]=1;
    while(n){
        if(n&1){
            for(int i=1;i<=2;i++)
                for(int j=1;j<=2;j++)
                    tmp[i][j]=ans[i][j],ans[i][j]=0;
            for(int i=1;i<=2;i++)
                for(int j=1;j<=2;j++)
                    for(int k=1;k<=2;k++)
                        ans[i][j]=(ans[i][j]+1LL*tmp[i][k]*base[k][j])%mod;
        }
        for(int i=1;i<=2;i++)
            for(int j=1;j<=2;j++)
                tmp[i][j]=base[i][j],base[i][j]=0;
        for(int i=1;i<=2;i++)
            for(int j=1;j<=2;j++)
                for(int k=1;k<=2;k++)
                    base[i][j]=(base[i][j]+1LL*tmp[i][k]*tmp[k][j])%mod;
        n>>=1;
    }
    return ans[2][1];
}

int main(){
    long long n;
    scanf("%lld",&n);
    printf("%d",solve(n));
    return 0;
}
